import { readFile, writeFile } from "node:fs/promises";

import { compile } from "json-schema-to-typescript";

const [, , inputPath = "src/lib/schema.contract.json", outputPath = "src/lib/schema.ts"] =
  process.argv;

const rawSchema = await readFile(inputPath, "utf-8");
const contractSchema = JSON.parse(rawSchema);
const generatedSource = await compile(contractSchema, "PreviewContract", {
  additionalProperties: false,
  bannerComment:
    "// Generated from `src/lib/schema.contract.json` by `preview/scripts/generate-schema-types.mjs`.\n// Do not edit this file manually.",
  ignoreMinAndMaxItems: true,
  style: {
    semi: true,
    singleQuote: false,
  },
  unreachableDefinitions: true,
  unknownAny: false,
});

await writeFile(outputPath, `${generatedSource.trim()}\n`, "utf-8");
